func:
var p = msg.payload;
// memoriza quem falou com o bot (usado para os alertas)
flow.set("chatId", p.chatId);

var txt = ("" + (p.content || "")).toLowerCase().trim();
if (txt[0] === "/") txt = txt.substring(1);

var map = {
  "ventilar": "VENTILAR_ON",
  "fechar": "VENTILAR_OFF",
  "auto": "AUTO",
  "silenciar": "MUTE",
  "reativar": "UNMUTE"
};
var cmd = map[txt];

if (cmd) {
  var ok = { payload: { chatId: p.chatId, type: "message",
    content: "\u2705 Comando enviado \u00e0 base: " + cmd } };
  return [ { payload: cmd }, ok ];   // saida1 -> comando MQTT | saida2 -> resposta
}

var help = { payload: { chatId: p.chatId, type: "message",
  content: "\ud83d\udef0\ufe0f AEGIS - comandos:\nventilar, fechar, auto, silenciar, reativar" } };
return [ null, help ];

var s = msg.payload;
if (!s || !s.estado) return null;

var chatId = flow.get("chatId");
if (!chatId) return null;   // mande uma msg ao bot primeiro p/ ele te conhecer

var anterior = flow.get("estadoAnterior");
if (s.estado === anterior) return null;   // so notifica quando o estado MUDA
flow.set("estadoAnterior", s.estado);

var hora = new Date().toLocaleTimeString("pt-BR");
var conf = Math.round((s.confianca || 0) * 100) + "%";
var texto;
if (s.estado === "NOMINAL") {
  texto = "\u2705 AEGIS: habitat voltou ao NOMINAL \u2014 " + hora;
} else {
  texto = "\ud83d\udef0\ufe0f\u26a0\ufe0f AEGIS ALERTA\nEstado: " + s.estado +
          " (" + conf + ")\nServo: " + s.servo + "\u00b0\n" + hora;
}
return { payload: { chatId: chatId, type: "message", content: texto } };
